public void testParseInto_monthDay_withZoneChange() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withLocale(Locale.UK);
    MutableDateTime result = new MutableDateTime(2004, 6, 15, 12, 30, 45, 500, NEWYORK);
    assertEquals(4, f.parseInto(result, "3 10", 0));
    assertEquals(new MutableDateTime(2004, 3, 10, 12, 30, 45, 500, NEWYORK), result);
}

public void testParseInto_monthDay_leapYear_march() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withLocale(Locale.UK);
    MutableDateTime result = new MutableDateTime(2004, 3, 15, 18, 45, 30, 250, TOKYO);
    assertEquals(4, f.parseInto(result, "3 1", 0));
    assertEquals(new MutableDateTime(2004, 3, 1, 18, 45, 30, 250, TOKYO), result);
}

public void testParseInto_monthDay_nonLeapYear_feb28() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withLocale(Locale.UK);
    MutableDateTime result = new MutableDateTime(2003, 1, 1, 0, 0, 0, 0, NEWYORK);
    assertEquals(4, f.parseInto(result, "2 28", 0));
    assertEquals(new MutableDateTime(2003, 2, 28, 0, 0, 0, 0, NEWYORK), result);
}

public void testParseInto_monthDay_endOfYear_differentZone() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withLocale(Locale.UK);
    MutableDateTime result = new MutableDateTime(2004, 12, 31, 23, 0, 0, 0, DateTimeZone.forOffsetHours(-8));
    assertEquals(4, f.parseInto(result, "1 15", 0));
    assertEquals(new MutableDateTime(2004, 1, 15, 23, 0, 0, 0, DateTimeZone.forOffsetHours(-8)), result);
}
